script.text:

function active$Voucher$(f) {
  objectBehavior$Voucher$Number.create(f, 'so_ct', 'ma_nk', 'ngay_ct', 'ma_dvcs');
  f.add_onResponseComplete(on$Voucher$ResponseComplete);
  f.add_commandEvent(on$Voucher$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$Voucher$DefaultValue(f);
  &ListCreate;
  &PostCreate;
}
/* <flatten type="Javascript"> */
function scatter$Voucher$(f) {
  f._voucherNumberBehavior.setFormLayout();
  set$Voucher$DefaultValue(f);
}
/* </flatten> */
function close$Voucher$(f) {
  try {f.remove_commandEvent(on$Voucher$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Voucher$ResponseComplete);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  objectBehavior$Voucher$Number.dispose(f);
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d05')._controlBehavior;
  switch (action) {
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;

      &VoucherNumberReading;
      &ListResponseTicket;

    case 'Reference':
      var g = f.getItem('d05')._controlBehavior;
      f.getItem('bp_ref').value = result[0].Value;
      set$Field$Key(g, 'ma_nv');
      break;
    default:
      break;
  }
}
function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d05'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function set$Voucher$DefaultValue(f) {
  if (f._action == 'New') {
    var d = new Date();
    f.setItemValue('ngay_ct', d);
  }
}
function onChange$Department(f) { f.request('Reference', 'Reference', ['ma_bp']); }

function set$Field$Key(g, c) {
  var o = g._activeCell, l = g._getColumnOrder(c);
  if (l == g._activeColumn) {
    if (o._controlBehavior) {
      var fields = g._fields, field = g._fields[l - 1], r = o.row, id = g.get_id();
      if (field.ItemKeyFilter) o._controlBehavior.set_completionKeyFilter($func.completionFilter(o, fields, field.ItemKeyFilter, r, id));
      if (field.ItemCheckFilter) o._controlBehavior.set_completionCheckFilter($func.completionFilter(o, fields, field.ItemCheckFilter, r, id));
    }
  }
}
/* </flatten> */
      &ListScript;
      &PostScript;

